#include <iostream>
#include <vector>
#include <numeric>
using namespace std;
class Solution {
  public:
    int sumSublist(vector<int>& nums, int k) {
      int sum = 0;
      for (int i = 0; i < nums.size(); i++) {
        sum += nums[i];
      }
      return sum;
    }
};
int main() {
  Solution solution;
  int nums[] = {1, 2, 3, 4, 5};
  int k = 3;
  int result = solution.sumSublist(vector<int>(nums, nums + 5), k);
  cout << "Sum of sublists: " << result << endl;
  return 0;
}
